          "source": "introduction",
          "confidence": 0.86
        },
        {
          "term": "data integration",
          "normalized": "数据整合",
          "std_label": null,
          "evidence": "SQL scripts merge the various data sources into a single schema",
          "source": "introduction",
          "confidence": 0.9
        },
        {
          "term": "high-resolution data",
          "normalized": "高分辨率数据",
          "std_label": null,
          "evidence": "HiRID contains high-resolution data for almost 34,000 admissions",
          "source": "introduction",
          "confidence": 0.91
        },
        {
          "term": "data acquisition",
          "normalized": "数据采集",
          "std_label": null,
          "evidence": "Data are acquired from the BIDMC data warehouse, the ICU information system",
          "source": "introduction",
          "confidence": 0.89
        },
        {
          "term": "database schema",
          "normalized": "数据库模式",
          "std_label": null,
          "evidence": "merge the various data sources into a single schema",
          "source": "introduction",
          "confidence": 0.87
        }
